async function sendEmailReceipt(req, res, next) {
  try {
    const { orderId, email } = req.body;

    if (!orderId || !email) return next(new Error("missing params"));

    const order = await Order.findById(orderId);
    if (!order) return next(new Error("order not found"));

    if (String(order.userId) !== String(req.user.id)) {
      return next(new Error("same_order verify failed"));
    }

    await Mailer.sendReceipt(email, order);

    res.json({ ok: true });
  } catch (err) {
    next(err);
  }
}
```

